////////////////                frame++;
////////////////                yield return new WaitForSeconds(delay);
////////////////                elapsed += delay;
////////////////            }
////////////////        }

////////////////        pigObject.SetActive(false);
////////////////        if (pigChatBox != null) pigChatBox.SetActive(false);

////////////////        onDone?.Invoke();
////////////////    }

////////////////    // ── Intro Sequence ────────────────────────────────────────────────────────

////////////////    /// <summary>
////////////////    /// Called by GameManager.ResetCleaningGame() to restart the intro after a Play Again.
////////////////    /// </summary>
////////////////    public void StartIntro()
////////////////    {
////////////////        GameLocked = true;
////////////////        StartCoroutine(PlayIntroSequence());
////////////////    }

////////////////    IEnumerator PlayIntroSequence()
////////////////    {
////////////////        if (pigObject == null) { UnlockGame(); yield break; }

////////////////        // Hide Okay button until animation finishes
////////////////        if (introOkayButton != null) introOkayButton.SetActive(false);

////////////////        // Show pig + intro text (NOT the gameplay chat box)
////////////////        Image pigImg = pigObject.GetComponent<Image>();
////////////////        pigObject.SetActive(true);
////////////////        if (introTextObject != null) introTextObject.SetActive(true);

////////////////        // Play pig animation looping for pigDisplayDuration seconds
////////////////        if (pigImg != null && pigFrames != null && pigFrames.Length > 0)
////////////////        {
