////////////////                frame++;
////////////////                yield return new WaitForSeconds(delay);
////////////////                elapsed += delay;
////////////////            }
////////////////        }
////////////////        else
////////////////        {
////////////////            yield return new WaitForSeconds(pigDisplayDuration);
////////////////        }

////////////////        // Show Okay button — game stays locked until player taps it
////////////////        if (introOkayButton != null) introOkayButton.SetActive(true);
////////////////    }

////////////////    /// <summary>
////////////////    /// Wire this to the Okay button's OnClick in the Inspector.
////////////////    /// </summary>
////////////////    public void OnOkayButtonClicked()
////////////////    {
////////////////        if (introOkayButton != null) introOkayButton.SetActive(false);
////////////////        if (introTextObject != null) introTextObject.SetActive(false);
////////////////        if (pigObject != null) pigObject.SetActive(false);
////////////////        UnlockGame();
////////////////    }

////////////////    static void UnlockGame() => GameLocked = false;

////////////////    // ── Reset ─────────────────────────────────────────────────────────────────

////////////////    public void ResetZone()
////////////////    {
////////////////        StopAllCoroutines();
////////////////        isCleaning = false;
////////////////        isClean = false;
////////////////        cleanedCount = 0;

////////////////        // Reset intro so it plays again on restart
////////////////        introPlayed = false;
////////////////        GameLocked = true;

////////////////        if (img != null)
////////////////        {
////////////////            img.sprite = defaultSprite;
////////////////            img.color = Color.white;
////////////////        }

////////////////        if (starObject != null) starObject.SetActive(false);
////////////////        if (finalStarObject != null) finalStarObject.SetActive(false);
////////////////        if (pigObject != null) pigObject.SetActive(false);
////////////////        if (pigChatBox != null) pigChatBox.SetActive(false);

////////////////        if (introOkayButton != null) introOkayButton.SetActive(false);
////////////////        if (introTextObject != null) introTextObject.SetActive(false);
////////////////    }
////////////////}

