////////////////        // 3. Unreadable texture — refuse and warn loudly
////////////////        if (!tex.isReadable)
////////////////        {
////////////////            Debug.LogError($"[PigPenZone] '{gameObject.name}': texture '{tex.name}' is NOT " +
