////////////////            yield return StartCoroutine(
////////////////                PlayStarNTimes(finalStarObject, finalStarFrames, finalStarFPS, finalStarPlayCount));

////////////////            if (allCleanPanel != null)
////////////////                allCleanPanel.SetActive(true);
////////////////        }
////////////////    }

