////////////////    static void ClearStatics() { allZones.Clear(); cleanedCount = 0; }

////////////////    void OnEnable() { if (!allZones.Contains(this)) allZones.Add(this); }
////////////////    void OnDisable() { allZones.Remove(this); }
////////////////    void OnDestroy() { allZones.Remove(this); }

